var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JANE_MASON_NULL_THIEF","text":{"KOREA":"흐음……. 강아지가 있다는 방이 여긴가?","JPN":"ふーん……仔犬がいる部屋ってここかしら？","ENG":"Hmm... Is this room where the puppy is?","TWN":"嗯……狗狗是在這個房間裡嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JANE_MASON_NULL_THIEF","text":{"KOREA":"후훗. 문짝부터 아주 으리으리한데. 값 나가는 물건도 많겠어.","JPN":"フフッ、入口からお金の匂いがするわね。高く売れそうな物も多いみたいだし。","ENG":"Hah hah. Even the door looks luxurious. I bet this room is filled with expensive things.","TWN":"呵呵～光是一個房間門就這麼華麗，裡面應該有很多值錢的東西吧？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JANE_MASON_NULL_THIEF","text":{"KOREA":"일 마치고 돌아가는 길에 몇 개 슬쩍해도 모르겠지?","JPN":"仕事帰りにこっそり何個か持ち帰ってもバレなさそうね？","ENG":"No one would notice if I nabbed a few on my way out, would they?","TWN":"等我把事情辦完，回去時順手偷些東西，應該不會有人發現吧？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"너에게 돌아갈 길은 없을 거다. 괴도 르블랑.","JPN":"あんたに持ち帰られるものなんてないぞ、怪盗ルブラン。","ENG":"Don't think you can go anywhere, LeBlanc the Thief.","TWN":"你確定你回得去嗎？怪盜布勒朗。"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아니…….","JPN":"いや……","ENG":"Or...","TWN":"還是我應該叫你……"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"<color=#ffd34c>제인 도우</color>라고 해야 하나.","JPN":"<color=#ffd34c>ジェーン・ドウ</color>と呼ぶべきか。","ENG":"Should I call you <color=#ffd34c>Jane Doe</color>?","TWN":"<color=#ffd34c>珍妮·多伊</color>？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"응? 이 목소리는……?","JPN":"あら？　この声は……？","ENG":"Mm? That voice...","TWN":"嗯？這個聲音是……？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"나다. 설마 모른다고 하진 않겠지.","JPN":"俺だ。まさか知らないとは言わないだろう。","ENG":"It's me. Don't pretend you don't know me.","TWN":"是我，你應該不會不認得我吧！"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"보상금 들고 튈 때부터 알아봤어야 했는데…….","JPN":"報奨金を持ち逃げされた時に気付くべきだったが……","ENG":"I should have known when you ran away with my money.","TWN":"自從你捲款潛逃後，我早該打聽一下……"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이제는 괴도라고? 아무리 불경기라지만 직업을 너무 함부로 고른 거 아닌가?","JPN":"怪盗だと？　いくら不景気とはいえ職業選びにこだわりが無さすぎじゃないか？","ENG":"You're a thief now, huh? Even if we're living in desperate times, shouldn't you be more careful in choosing your job?","TWN":"你現在是怪盜？就算再怎麼不景氣，你找工作是不是找得太隨便啦？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"원래 진로를 결정하기 전에 이것저것 체험해 봐야 하지 않겠어?","JPN":"進路というのはね、決める前に色々と体験してみるべきなのよ。","ENG":"Shouldn't people at least try a few different things before choosing their career path?","TWN":"在決定出路前，不是本來就應該多嘗試嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"이번 건 꽤 적성에 맞는 것 같아서 고민 중이야.","JPN":"今回は結構性に合っているみたいで、悩んでいるの。","ENG":"I'm seriously thinking of staying at this job. I think it's my thing.","TWN":"這份的工作好像滿適合我的，所以我也滿苦惱的。 "},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"적성이고 나발이고 훔쳐간 보상금이나 내놔!","JPN":"性に合うもクソも無い、盗んでいった報奨金を返せ！","ENG":"Your thing or not, give me my money back!","TWN":"我管你適不適合，把我的獎金還來！"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"네가 보상금 들고 사라지는 바람에 우리 사무소는 길거리에 나앉게 생겼다고!","JPN":"あんたに報奨金を盗まれたせいで、事務所が破産寸前なんだぞ！","ENG":"Because you ran with my money, the business is on the verge of bankruptcy!","TWN":"都是因為你捲款潛逃，害我們事務所只能淪落街頭！"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"우리 사이에 섭섭하게 왜 그래. 내가 그 돈으로 나쁜 짓 할 여자 아닌 거 다 알면서.","JPN":"あら、そんな冷たいこと言わないでよ。アタシがあの金で悪いことをする女じゃないことくらい、知ってるでしょ？","ENG":"Come on, we've been through a lot together. You know I wouldn't do anything bad with your money.","TWN":"火氣幹嘛這麼大～你明知道我不會拿那筆錢去幹壞事～"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 그 돈 없어도 나쁜 짓 할 인간이긴 하지.","JPN":"そうだな。あの金がなくても悪いことをする人間だった。","ENG":"Well. I do know you'd do bad things with or without my money.","TWN":"沒錯，你就算沒有那筆錢，也會幹壞事！"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"칭찬 고마워, 동생.","JPN":"お褒めいただきありがとう、弟クン。","ENG":"Thank you, brother. I'll take that as a compliment.","TWN":"謝謝你的讚美，小老弟～"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"그나저나 이제 그만 자리 좀 비켜 줄래? 내 진로 선택에 방해가 되거든?","JPN":"ていうか、そろそろそこを退いてくれない？　アタシの進路選択の邪魔になるから。","ENG":"Now, could you get out my way? You're interfering with my career choice!","TWN":"不過你可以閃開嗎？你妨礙到姊姊的出路囉～"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그렇다고 다짜고짜 칼을 던지냐?!","JPN":"そんなこと言っていきなりナイフを投げるのは卑怯じゃないか！？","ENG":"You didn't have to throw knives at me!","TWN":"你竟然拿刀扔我？！"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L27_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"알잖아. 원래 미래 없이 방황하는 청소년은 세상 무서운 걸 몰라.","JPN":"行き場を失って彷徨う女の子ほど怖いもの知らずなものよ。わかってるくせに。","ENG":"You know a wandering teenager with no future ahead of them has nothing to fear.","TWN":"拜託～像我這種不知道未來在哪裡的青少年，還有什麼好怕的？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"아차, 경험자 앞에서 너무 무게 잡았나?","JPN":"あら、経験者の前で余計なことを言ってしまったかしら？","ENG":"Oh, wait. You know that better than I do, don't you?","TWN":"哎呀，在你面前我根本是小巫見大巫吧？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"네가 진짜 청소년인 줄 알아?!","JPN":"いい年して女の子はないだろ。","ENG":"You're not a teenager!","TWN":"你還真以為你是青少年嗎？！"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그리고 적어도 난 사람한테 칼 던진 적은 없어!","JPN":"少なくとも、俺は人に向かってナイフを投げたことなんてないぞ！","ENG":"Also, I've never thrown knives at people!","TWN":"再說我至少不會拿刀丟人！"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"애초에 맞으라고 던진 것도 아닌데 야단은.","JPN":"当てるつもりで投げたわけでもないのに、そう熱くならないでよ。","ENG":"Don't be a drama queen. I didn't really throw them to hit you.","TWN":"大驚小怪什麼，我又不是真的要扔中你，不過是嚇唬你而已～"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"그러게 비키라니까? 눈에 훤히 보이게 깔아 둔 함정 믿고 까불면 누나한테 혼난다?","JPN":"だから退いてくれない？　見え見えの罠ばかり仕掛けてドヤ顔されても、お姉ちゃんは困っちゃうわよ。","ENG":"Now, get out my way, will you? Don't think your obvious traps can stop me or you are going to get hurt.","TWN":"好狗不擋路！還是你以為那些明顯的陷阱能夠抓到我？你再這樣不聽話，姊姊要生氣囉？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"웃기지 마시지, 좀도둑 아가씨.","JPN":"笑わせるな、こそ泥娘が。","ENG":"Screw you, petty thief.","TWN":"你要笑死我，小偷姊姊。"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내가 있는 한 방에 들어갈 생각은 안 하는 게 좋을 거야.","JPN":"俺がいる限り、その部屋には入らせないぞ。","ENG":"You can't go in there as long as I'm here.","TWN":"只要有我在，勸你最好打消進去房間的念頭。"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"그래? 들어가면 어쩔 건데?","JPN":"あら、そう？　入ったらどうする？","ENG":"Oh, yeah? What if I try?","TWN":"是嗎？我偏要進去，你能拿我怎麼樣？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……후회하게 될 거다.","JPN":"……後悔するぞ。","ENG":"I'll make you regret it.","TWN":"……我會讓你悔不當初。"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"흐음. 아무래도 단단히 미운 털이 박힌 것 같네.","JPN":"ふーん。どうやらかなり拗ねちゃったみたいね。","ENG":"Hmm... I see you don't love me anymore.","TWN":"嗯，果然是有夠討厭的。"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"하지만 이쪽도 다 어른의 사정이 있어서 말이야.","JPN":"でも、こっちだって大人の事情っていうものがあるの。","ENG":"I'm sorry I can't explain everything to you. Grown-up issues.","TWN":"不過姊姊有大人的事要辦。"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"거기서 가만히 보고 있어. 이 누나가 눈 깜짝할 새…….","JPN":"だからそこで大人しくしていてね。お姉ちゃんがあっという間に……","ENG":"You just stay there and watch. I'll be in and out with a blink—","TWN":"你就好好看著，看姊姊怎麼……"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"뭐야, 이 와이어는!? 발에 묶여선……!","JPN":"な、なによ、このワイヤーは！？　足首に……！","ENG":"Huh? Where did this wire come from? I can't move!","TWN":"怎麼會這樣！鋼絲怎麼會綁住我的腳……！"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다른 함정들은 원래부터 전부 눈속임이었단 거지.","JPN":"他の罠は本命じゃない。","ENG":"All the other traps were just decoys.","TWN":"你看到的那些陷阱，都只是障眼法而已。"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"원래 사람은 결승점 앞에서 제일 방심하는 법이거든.","JPN":"人っていうのは、ゴールの前でつい油断してしまうものだ。","ENG":"People usually let their guard down right before the finish line.","TWN":"人在終點前，才是最容易鬆懈的時候。"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"자, 다치기 전에 얌전히 투항하시지!!","JPN":"さあ、ケガをする前に大人しく降参しろ！！","ENG":"Now, surrender when I ask nicely!","TWN":"乖乖投降吧！！否則受傷我可不負責。"},"stage":{"bg":"HALL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};